#!/bin/bash
set -e
echo "════════════════════════════════════════════════════════"
echo " F38B — Student 360° Profile Preview — FRONTEND fix script"
echo "════════════════════════════════════════════════════════"

WORKDIR=$(mktemp -d); cd "$WORKDIR"

cat > patch_f38b_frontend.js << 'PRNODEEOF'

const fs = require('fs');
const path = require('path');

const CANDIDATES = [
  process.env.APP_DIR,
  '/root/workspace/frontend/app',
  '/home/runner/workspace/frontend/app',
  path.join(process.cwd(), 'frontend/app'),
].filter(Boolean);

let TARGET = null;
for (const dir of CANDIDATES) {
  const p1 = path.join(dir, 'admin', 'x7k2p', 'page.tsx');
  const p2 = path.join(dir, 'admin', 'page.tsx');
  if (fs.existsSync(p1)) { TARGET = p1; break; }
  if (fs.existsSync(p2)) { TARGET = p2; break; }
}
if (!TARGET) {
  console.error('❌ Could not find the admin panel page.tsx automatically.');
  console.error('   Set APP_DIR env var, e.g.:');
  console.error('   APP_DIR=/home/runner/workspace/frontend/app node patch_f38b_frontend.js');
  process.exit(1);
}
console.log('📄 Target file:', TARGET);

let src = fs.readFileSync(TARGET, 'utf8');
const before = src;
let count = 0;

// ── 1) Add new state declarations ──
{
  const anchor = "const [selStudent,setSelStudent]=useState<Student|null>(null)";
  const addition = anchor + `
  // F38B — Student 360° Profile Preview (Superadmin only)
  const [previewStudent,setPreviewStudent]=useState<any>(null)
  const [previewData,setPreviewData]=useState<any>(null)
  const [previewLoading,setPreviewLoading]=useState(false)
  const [previewSection,setPreviewSection]=useState('personal')
  const [previewTimelineFilter,setPreviewTimelineFilter]=useState('all')
  const openStudentPreview=async(s:any)=>{
    setPreviewStudent(s);setPreviewData(null);setPreviewSection('personal');setPreviewTimelineFilter('all');setPreviewLoading(true)
    try{
      const r=await fetch(\`\${API}/api/admin/student-preview/\${s._id}\`,{headers:{Authorization:\`Bearer \${token}\`}})
      const d=await r.json()
      if(r.ok&&d.success)setPreviewData(d)
      else{T(d.message||'Failed to load profile preview','e');setPreviewData(null)}
    }catch(e){T('Network error','e');setPreviewData(null)}
    setPreviewLoading(false)
  }`;
  if (src.includes(anchor) && !src.includes('openStudentPreview')) {
    src = src.replace(anchor, addition);
    count++;
    console.log('✅ Patched: added F38B state + openStudentPreview() function');
  } else if (src.includes('openStudentPreview')) {
    console.log('⚠️  openStudentPreview already present — skipping state patch');
  } else {
    console.log('❌ Could not find selStudent state anchor — state patch NOT applied');
  }
}

// ── 2) Add "🔍 360°" button next to existing "👁️ View" button (superadmin only) ──
{
  const anchor = `<button onClick={(e:any)=>{e.stopPropagation();setSelStudent(s)}} style={{...bg_,fontSize:10,padding:'6px 10px'}}>👁️ View</button>`;
  const addition = anchor + `
                            {typeof window!=='undefined'&&localStorage.getItem('pr_role')==='superadmin'&&(
                              <button onClick={(e:any)=>{e.stopPropagation();openStudentPreview(s)}} style={{...bg_,fontSize:10,padding:'6px 10px',border:'1px solid rgba(167,139,250,0.4)',color:'#A78BFA',background:'rgba(167,139,250,0.08)'}}>🧬 360°</button>
                            )}`;
  if (src.includes(anchor) && !src.includes('🧬 360°')) {
    src = src.replace(anchor, addition);
    count++;
    console.log('✅ Patched: added "🧬 360°" preview button next to View button');
  } else if (src.includes('🧬 360°')) {
    console.log('⚠️  360° button already present — skipping');
  } else {
    console.log('❌ Could not find the "👁️ View" button anchor — button NOT added');
  }
}

// ── 3) Insert the full-screen modal JSX block ──
{
  const anchor = "{/* ── ARCHIVED STUDENTS (SuperAdmin only, deleted filter) ── */}";
  const modalBlock = "              {/* ══════════════════════════════════════════════════════════\n                  F38B — STUDENT 360° PROFILE PREVIEW (Superadmin ONLY)\n                  ══════════════════════════════════════════════════════════ */}\n              {previewStudent&&typeof window!=='undefined'&&localStorage.getItem('pr_role')==='superadmin'&&(\n                <div onKeyDown={(e:any)=>{if(e.key==='Escape')setPreviewStudent(null)}} tabIndex={-1} style={{position:'fixed' as const,top:0,left:0,right:0,bottom:0,background:'rgba(0,0,0,0.88)',backdropFilter:'blur(8px)',zIndex:10000,display:'flex',flexDirection:'column' as const,animation:'fadeUp 0.25s ease'}}>\n                  {/* Sticky top header */}\n                  <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'14px 20px',borderBottom:'1px solid rgba(77,159,255,0.15)',background:'rgba(0,10,20,0.95)',flexWrap:'wrap' as const,gap:10}}>\n                    <div style={{display:'flex',alignItems:'center',gap:12,flexWrap:'wrap' as const}}>\n                      <span style={{fontSize:20}}>🧬</span>\n                      <div>\n                        <div style={{fontFamily:'Playfair Display,serif',fontSize:15,fontWeight:700,color:'#E8F4FD'}}>{previewData?.header?.name||previewStudent.name} — 360° Profile</div>\n                        <div style={{fontSize:10,color:'#8899AA',marginTop:2,display:'flex',gap:8,flexWrap:'wrap' as const}}>\n                          {previewData?.header?.studentId&&<span style={{fontFamily:'monospace',color:'#4D9FFF',fontWeight:700}}>{previewData.header.studentId}</span>}\n                          {previewData&&<span style={{color:previewData.verification?.email==='verified'?'#00C48C':'#FFB84D'}}>{previewData.verification?.email==='verified'?'✓ Verified':'⏳ Unverified'}</span>}\n                          {previewData&&<span>📊 {previewData.header?.completion}% complete</span>}\n                          {previewData&&<span style={{textTransform:'capitalize' as const}}>● {previewData.header?.status}</span>}\n                        </div>\n                      </div>\n                    </div>\n                    <button onClick={()=>setPreviewStudent(null)} style={{background:'rgba(255,71,87,0.12)',border:'1px solid rgba(255,71,87,0.3)',color:'#FF4757',borderRadius:8,padding:'6px 14px',cursor:'pointer',fontSize:13,fontWeight:700}}>✕ Close</button>\n                  </div>\n\n                  {previewLoading?(\n                    <div style={{flex:1,display:'flex',alignItems:'center',justifyContent:'center',color:'#8899AA',fontSize:13}}>⟳ Loading 360° profile…</div>\n                  ):!previewData?(\n                    <div style={{flex:1,display:'flex',alignItems:'center',justifyContent:'center',color:'#FF4757',fontSize:13}}>Failed to load profile preview.</div>\n                  ):(\n                  <div style={{flex:1,display:'flex',overflow:'hidden',flexWrap:'wrap' as const}}>\n\n                    {/* ── LEFT SUMMARY PANEL ── */}\n                    <div style={{width:220,flexShrink:0,borderRight:'1px solid rgba(77,159,255,0.12)',padding:'18px 14px',overflowY:'auto' as const,background:'rgba(0,14,28,0.6)'}}>\n                      <div style={{width:64,height:64,borderRadius:16,margin:'0 auto 10px',overflow:'hidden',background:'linear-gradient(135deg,#4D9FFF,#0055CC)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:24,fontWeight:800,color:'#fff'}}>\n                        {previewData.personal?.avatar?<img src={previewData.personal.avatar} style={{width:'100%',height:'100%',objectFit:'cover'}}/>:(previewData.personal?.name||'?').charAt(0).toUpperCase()}\n                      </div>\n                      <div style={{textAlign:'center' as const,fontWeight:700,fontSize:13,color:'#E8F4FD',marginBottom:2}}>{previewData.personal?.name}</div>\n                      <div style={{textAlign:'center' as const,fontSize:10,color:'#8899AA',marginBottom:10}}>{previewData.personal?.email}</div>\n                      {previewData.personal?.studentId&&<div style={{display:'flex',justifyContent:'center',alignItems:'center',gap:5,marginBottom:12}}><span style={{fontFamily:'monospace',fontSize:10,fontWeight:800,color:'#FFD700',letterSpacing:1}}>{previewData.personal.studentId}</span><CopyBtn text={previewData.personal.studentId} size=\"sm\"/></div>}\n\n                      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:6,marginBottom:14}}>\n                        {[{l:'Health',v:`${previewData.verification?.healthScore??0}`,c:'#00C48C'},{l:'Complete',v:`${previewData.header?.completion??0}%`,c:'#4D9FFF'},{l:'Exams',v:previewData.quickInspect?.totalExams??0,c:'#FFD700'},{l:'Streak',v:previewData.academic?.snapshot?.currentStreak??0,c:'#FF8A00'}].map((x,i)=>(\n                          <div key={i} style={{background:'rgba(0,22,40,0.7)',border:'1px solid rgba(77,159,255,0.1)',borderRadius:8,padding:'6px 4px',textAlign:'center' as const}}>\n                            <div style={{fontSize:13,fontWeight:800,color:x.c}}>{x.v}</div>\n                            <div style={{fontSize:8,color:'#8899AA',textTransform:'uppercase' as const}}>{x.l}</div>\n                          </div>\n                        ))}\n                      </div>\n\n                      <div style={{fontSize:9,color:'#8899AA',textTransform:'uppercase' as const,fontWeight:700,letterSpacing:0.6,marginBottom:6}}>Quick Actions</div>\n                      <div style={{display:'flex',flexDirection:'column' as const,gap:5}}>\n                        {[\n                          {l:'📋 Copy Student ID',fn:()=>{if(previewData.personal?.studentId){navigator.clipboard.writeText(previewData.personal.studentId);T('Copied!','s')}}},\n                          {l:'🔐 Jump to Security',fn:()=>setPreviewSection('security')},\n                          {l:'📸 Photo History',fn:()=>setPreviewSection('photos')},\n                          {l:'🕐 Audit Timeline',fn:()=>setPreviewSection('audit')},\n                        ].map((a,i)=>(\n                          <button key={i} onClick={a.fn} style={{textAlign:'left' as const,background:'rgba(77,159,255,0.06)',border:'1px solid rgba(77,159,255,0.15)',color:'#8FB8E8',borderRadius:8,padding:'7px 10px',fontSize:10,cursor:'pointer'}}>{a.l}</button>\n                        ))}\n                      </div>\n\n                      <div style={{fontSize:9,color:'#8899AA',textTransform:'uppercase' as const,fontWeight:700,letterSpacing:0.6,margin:'14px 0 6px'}}>Sections</div>\n                      <div style={{display:'flex',flexDirection:'column' as const,gap:4}}>\n                        {[\n                          {k:'personal',l:'👤 Personal'},{k:'academic',l:'🎓 Academic'},{k:'security',l:'🔒 Security'},\n                          {k:'login',l:'🕐 Login Activity'},{k:'photos',l:'📸 Photo History'},\n                          {k:'timeline',l:'📝 Field Timeline'},{k:'audit',l:'🛡️ Audit Trail'},\n                        ].map(s=>(\n                          <button key={s.k} onClick={()=>setPreviewSection(s.k)} style={{\n                            textAlign:'left' as const,padding:'7px 10px',borderRadius:8,fontSize:11,cursor:'pointer',\n                            background:previewSection===s.k?'rgba(77,159,255,0.18)':'transparent',\n                            color:previewSection===s.k?'#4D9FFF':'#8899AA',\n                            border:'none',fontWeight:previewSection===s.k?700:500,\n                          }}>{s.l}</button>\n                        ))}\n                      </div>\n                    </div>\n\n                    {/* ── MAIN WORKSPACE ── */}\n                    <div style={{flex:1,minWidth:280,padding:'20px',overflowY:'auto' as const}}>\n\n                      {previewSection==='personal'&&(\n                        <div>\n                          <div style={{fontWeight:700,fontSize:13,color:'#4D9FFF',marginBottom:14}}>👤 Personal Details</div>\n                          <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(160px,1fr))',gap:10,marginBottom:18}}>\n                            {[['Full Name',previewData.personal?.name],['Email',previewData.personal?.email],['Phone',previewData.personal?.phone||'—'],['DOB',previewData.personal?.dob||'—'],['Gender',previewData.personal?.gender||'—'],['State',previewData.personal?.state||'—'],['City',previewData.personal?.city||'—']].map(([l,v],i)=>(\n                              <div key={i} style={{background:'rgba(0,22,40,0.7)',border:'1px solid rgba(77,159,255,0.1)',borderRadius:10,padding:'10px 12px'}}>\n                                <div style={{fontSize:9,color:'#8899AA',textTransform:'uppercase' as const,marginBottom:3}}>{l}</div>\n                                <div style={{fontSize:12,color:'#E8F4FD',fontWeight:600}}>{v as any}</div>\n                              </div>\n                            ))}\n                          </div>\n                          {previewData.personal?.bio&&<div style={{marginBottom:18}}><div style={{fontSize:9,color:'#8899AA',textTransform:'uppercase' as const,marginBottom:4}}>Bio</div><div style={{fontSize:12,color:'#E8F4FD',background:'rgba(0,22,40,0.7)',borderRadius:10,padding:'10px 12px',border:'1px solid rgba(77,159,255,0.1)'}}>{previewData.personal.bio}</div></div>}\n                          <div style={{fontSize:10,color:'#8899AA'}}>✅ Profile Completion: <b style={{color:'#4D9FFF'}}>{previewData.personal?.completion}%</b></div>\n                        </div>\n                      )}\n\n                      {previewSection==='academic'&&(\n                        <div>\n                          <div style={{fontWeight:700,fontSize:13,color:'#4D9FFF',marginBottom:14}}>🎓 Academic Profile</div>\n                          <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(160px,1fr))',gap:10,marginBottom:20}}>\n                            {[['Target Exam',previewData.academic?.targetExam||'—'],['Target Year',previewData.academic?.targetYear||'—'],['Board',previewData.academic?.board||'—'],['School',previewData.academic?.school||'—'],['Medium',previewData.academic?.medium||'—'],['Batch',previewData.academic?.batch||'—']].map(([l,v],i)=>(\n                              <div key={i} style={{background:'rgba(0,22,40,0.7)',border:'1px solid rgba(77,159,255,0.1)',borderRadius:10,padding:'10px 12px'}}>\n                                <div style={{fontSize:9,color:'#8899AA',textTransform:'uppercase' as const,marginBottom:3}}>{l}</div>\n                                <div style={{fontSize:12,color:'#E8F4FD',fontWeight:600}}>{v as any}</div>\n                              </div>\n                            ))}\n                          </div>\n                          <div style={{fontWeight:700,fontSize:11,color:'#8899AA',marginBottom:10,textTransform:'uppercase' as const}}>📊 Academic Snapshot</div>\n                          <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(110px,1fr))',gap:10}}>\n                            {[['Total Exams',previewData.academic?.snapshot?.totalExams],['Best Score',previewData.academic?.snapshot?.bestScore],['Avg Score',previewData.academic?.snapshot?.avgScore],['Streak',previewData.academic?.snapshot?.currentStreak]].map(([l,v],i)=>(\n                              <div key={i} style={{background:'rgba(77,159,255,0.06)',border:'1px solid rgba(77,159,255,0.15)',borderRadius:10,padding:'10px',textAlign:'center' as const}}>\n                                <div style={{fontSize:16,fontWeight:800,color:'#4D9FFF'}}>{v as any}</div>\n                                <div style={{fontSize:9,color:'#8899AA'}}>{l}</div>\n                              </div>\n                            ))}\n                          </div>\n                        </div>\n                      )}\n\n                      {previewSection==='security'&&(\n                        <div>\n                          <div style={{fontWeight:700,fontSize:13,color:'#4D9FFF',marginBottom:14}}>🔒 Security</div>\n                          <div style={{fontSize:10,color:'#00C48C',background:'rgba(0,196,140,0.08)',border:'1px solid rgba(0,196,140,0.2)',borderRadius:8,padding:'8px 12px',marginBottom:14}}>🔐 Actual password / hash is never shown — metadata only.</div>\n                          <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(160px,1fr))',gap:10,marginBottom:18}}>\n                            {[\n                              ['Password Last Changed',previewData.security?.passwordLastChangedAt?new Date(previewData.security.passwordLastChangedAt).toLocaleString('en-IN'):'Never'],\n                              ['Password Change Count',previewData.security?.passwordChangeCount??0],\n                              ['2FA Status',previewData.security?.twoFactorEnabled?'✅ Enabled':'❌ Disabled'],\n                              ['Active Devices',previewData.security?.activeDeviceCount??1],\n                              ['Trusted Devices',previewData.security?.trustedDevices?.length??0],\n                              ['Failed Login Attempts',previewData.security?.failedLoginAttempts??0],\n                            ].map(([l,v],i)=>(\n                              <div key={i} style={{background:'rgba(0,22,40,0.7)',border:'1px solid rgba(77,159,255,0.1)',borderRadius:10,padding:'10px 12px'}}>\n                                <div style={{fontSize:9,color:'#8899AA',textTransform:'uppercase' as const,marginBottom:3}}>{l}</div>\n                                <div style={{fontSize:12,color:'#E8F4FD',fontWeight:600}}>{v as any}</div>\n                              </div>\n                            ))}\n                          </div>\n                          <div style={{fontWeight:700,fontSize:11,color:'#8899AA',marginBottom:10,textTransform:'uppercase' as const}}>📱 Device Intelligence</div>\n                          {(previewData.deviceIntelligence||[]).length===0?<div style={{fontSize:11,color:'#8899AA'}}>No devices recorded yet.</div>:(\n                            <div style={{display:'flex',flexDirection:'column' as const,gap:8}}>\n                              {previewData.deviceIntelligence.map((d:any,i:number)=>(\n                                <div key={i} style={{background:'rgba(0,22,40,0.7)',border:'1px solid rgba(77,159,255,0.1)',borderRadius:10,padding:'10px 12px',display:'flex',justifyContent:'space-between',flexWrap:'wrap' as const,gap:6}}>\n                                  <div style={{fontSize:11,color:'#E8F4FD'}}>💻 {d.label}</div>\n                                  <div style={{fontSize:10,color:'#8899AA'}}>First: {d.firstSeen?new Date(d.firstSeen).toLocaleDateString('en-IN'):'—'} · Last: {d.lastSeen?new Date(d.lastSeen).toLocaleDateString('en-IN'):'—'}</div>\n                                </div>\n                              ))}\n                            </div>\n                          )}\n                        </div>\n                      )}\n\n                      {previewSection==='login'&&(\n                        <div>\n                          <div style={{fontWeight:700,fontSize:13,color:'#4D9FFF',marginBottom:14}}>🕐 Login Activity</div>\n                          {(previewData.loginActivity||[]).length===0?<div style={{fontSize:11,color:'#8899AA'}}>No login activity recorded.</div>:(\n                            <div style={{display:'flex',flexDirection:'column' as const,gap:7}}>\n                              {previewData.loginActivity.map((l:any,i:number)=>(\n                                <div key={i} style={{background:'rgba(0,22,40,0.7)',border:'1px solid rgba(77,159,255,0.1)',borderRadius:10,padding:'9px 12px',display:'flex',justifyContent:'space-between',flexWrap:'wrap' as const,gap:6}}>\n                                  <div style={{fontSize:11,color:'#E8F4FD'}}>📍 {l.city||'Unknown'}, {l.country||''} · {l.device||'—'}</div>\n                                  <div style={{fontSize:10,color:'#8899AA'}}>{l.loginTime?new Date(l.loginTime).toLocaleString('en-IN'):'—'} · {l.ip}</div>\n                                </div>\n                              ))}\n                            </div>\n                          )}\n                        </div>\n                      )}\n\n                      {previewSection==='photos'&&(\n                        <div>\n                          <div style={{fontWeight:700,fontSize:13,color:'#4D9FFF',marginBottom:14}}>📸 Profile Photo History</div>\n                          {(previewData.photoHistory||[]).length===0?<div style={{fontSize:11,color:'#8899AA'}}>No photo changes recorded.</div>:(\n                            <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(100px,1fr))',gap:12}}>\n                              {previewData.photoHistory.map((p:any,i:number)=>(\n                                <div key={i} style={{textAlign:'center' as const}}>\n                                  <div style={{width:'100%',aspectRatio:'1',borderRadius:10,overflow:'hidden',border:p.label==='current'?'2px solid #00C48C':'1px solid rgba(77,159,255,0.2)',marginBottom:5}}>\n                                    <img src={p.url} style={{width:'100%',height:'100%',objectFit:'cover'}}/>\n                                  </div>\n                                  <div style={{fontSize:9,color:p.label==='current'?'#00C48C':'#8899AA',fontWeight:700}}>{p.label==='current'?'CURRENT':'PREVIOUS'}</div>\n                                  <div style={{fontSize:8,color:'#8899AA'}}>{p.at?new Date(p.at).toLocaleDateString('en-IN'):''}</div>\n                                </div>\n                              ))}\n                            </div>\n                          )}\n                        </div>\n                      )}\n\n                      {previewSection==='timeline'&&(\n                        <div>\n                          <div style={{fontWeight:700,fontSize:13,color:'#4D9FFF',marginBottom:10}}>📝 Field Change Timeline</div>\n                          <div style={{display:'flex',gap:6,marginBottom:14,flexWrap:'wrap' as const}}>\n                            {['all','personal','academic','security'].map(f=>(\n                              <button key={f} onClick={()=>setPreviewTimelineFilter(f)} style={{\n                                padding:'5px 12px',borderRadius:8,fontSize:10,cursor:'pointer',textTransform:'capitalize' as const,\n                                border:`1px solid ${previewTimelineFilter===f?'#4D9FFF':'rgba(77,159,255,0.15)'}`,\n                                background:previewTimelineFilter===f?'rgba(77,159,255,0.15)':'transparent',\n                                color:previewTimelineFilter===f?'#4D9FFF':'#8899AA',\n                              }}>{f}</button>\n                            ))}\n                          </div>\n                          {(previewData.fieldChangeTimeline||[]).filter((c:any)=>previewTimelineFilter==='all'||c.category===previewTimelineFilter).length===0?<div style={{fontSize:11,color:'#8899AA'}}>No field changes recorded.</div>:(\n                            <div style={{display:'flex',flexDirection:'column' as const,gap:8}}>\n                              {previewData.fieldChangeTimeline.filter((c:any)=>previewTimelineFilter==='all'||c.category===previewTimelineFilter).map((c:any,i:number)=>(\n                                <div key={i} style={{background:'rgba(0,22,40,0.7)',border:'1px solid rgba(77,159,255,0.1)',borderRadius:10,padding:'10px 12px'}}>\n                                  <div style={{display:'flex',justifyContent:'space-between',marginBottom:5,flexWrap:'wrap' as const,gap:6}}>\n                                    <span style={{fontSize:11,fontWeight:700,color:'#E8F4FD',textTransform:'capitalize' as const}}>{c.field}</span>\n                                    <span style={{fontSize:9,color:'#8899AA'}}>{c.updatedAt?new Date(c.updatedAt).toLocaleString('en-IN'):''}</span>\n                                  </div>\n                                  <div style={{fontSize:10,color:'#8899AA'}}>Old: <span style={{color:'#FF8A80'}}>{String(c.oldValue??'—')}</span> → New: <span style={{color:'#00C48C'}}>{String(c.newValue??'—')}</span></div>\n                                  <div style={{fontSize:9,color:'#8899AA',marginTop:3}}>Source: {c.source} · By: {c.updatedBy}</div>\n                                </div>\n                              ))}\n                            </div>\n                          )}\n                        </div>\n                      )}\n\n                      {previewSection==='audit'&&(\n                        <div>\n                          <div style={{fontWeight:700,fontSize:13,color:'#4D9FFF',marginBottom:14}}>🛡️ Audit Trail (Admin Actions)</div>\n                          {(previewData.auditTrail||[]).length===0?<div style={{fontSize:11,color:'#8899AA'}}>No admin actions recorded on this student yet.</div>:(\n                            <div style={{display:'flex',flexDirection:'column' as const,gap:8}}>\n                              {previewData.auditTrail.map((a:any,i:number)=>(\n                                <div key={i} style={{background:'rgba(0,22,40,0.7)',border:'1px solid rgba(77,159,255,0.1)',borderRadius:10,padding:'10px 12px'}}>\n                                  <div style={{fontSize:11,fontWeight:700,color:'#E8F4FD'}}>{a.action}</div>\n                                  <div style={{fontSize:10,color:'#8899AA',marginTop:3}}>{a.details}</div>\n                                  <div style={{fontSize:9,color:'#8899AA',marginTop:3}}>{a.createdAt?new Date(a.createdAt).toLocaleString('en-IN'):''}</div>\n                                </div>\n                              ))}\n                            </div>\n                          )}\n                        </div>\n                      )}\n                    </div>\n\n                    {/* ── RIGHT TIMELINE PANEL ── */}\n                    <div style={{width:230,flexShrink:0,borderLeft:'1px solid rgba(77,159,255,0.12)',padding:'18px 14px',overflowY:'auto' as const,background:'rgba(0,14,28,0.6)'}}>\n                      <div style={{fontSize:9,color:'#8899AA',textTransform:'uppercase' as const,fontWeight:700,letterSpacing:0.6,marginBottom:10}}>🔍 Quick Inspect</div>\n                      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:6,marginBottom:16}}>\n                        {[['Login Count',previewData.quickInspect?.loginCount],['Failed Logins',previewData.quickInspect?.failedLogins],['Photo Changes',previewData.quickInspect?.photoChanges],['Best Score',previewData.quickInspect?.bestScore]].map(([l,v],i)=>(\n                          <div key={i} style={{background:'rgba(0,22,40,0.7)',border:'1px solid rgba(77,159,255,0.1)',borderRadius:8,padding:'7px',textAlign:'center' as const}}>\n                            <div style={{fontSize:13,fontWeight:800,color:'#4D9FFF'}}>{v as any}</div>\n                            <div style={{fontSize:8,color:'#8899AA'}}>{l}</div>\n                          </div>\n                        ))}\n                      </div>\n\n                      <div style={{fontSize:9,color:'#8899AA',textTransform:'uppercase' as const,fontWeight:700,letterSpacing:0.6,marginBottom:10}}>📈 Change Frequency</div>\n                      {(previewData.changeFrequency||[]).length===0?<div style={{fontSize:10,color:'#8899AA',marginBottom:16}}>No changes yet.</div>:(\n                        <div style={{marginBottom:16}}>\n                          {previewData.changeFrequency.slice(0,5).map((c:any,i:number)=>(\n                            <div key={i} style={{display:'flex',justifyContent:'space-between',fontSize:10,padding:'4px 0',borderBottom:'1px solid rgba(77,159,255,0.08)'}}>\n                              <span style={{color:'#E8F4FD',textTransform:'capitalize' as const}}>{c.field}</span>\n                              <span style={{color:'#4D9FFF',fontWeight:700}}>{c.count}×</span>\n                            </div>\n                          ))}\n                        </div>\n                      )}\n\n                      <div style={{fontSize:9,color:'#8899AA',textTransform:'uppercase' as const,fontWeight:700,letterSpacing:0.6,marginBottom:10}}>⚠️ Risk Indicator</div>\n                      <div style={{fontSize:11,fontWeight:700,padding:'8px 12px',borderRadius:8,textAlign:'center' as const,\n                        background:previewData.verification?.riskIndicator==='high'?'rgba(255,71,87,0.12)':previewData.verification?.riskIndicator==='medium'?'rgba(255,184,77,0.12)':'rgba(0,196,140,0.12)',\n                        color:previewData.verification?.riskIndicator==='high'?'#FF4757':previewData.verification?.riskIndicator==='medium'?'#FFB84D':'#00C48C',\n                      }}>{(previewData.verification?.riskIndicator||'low').toUpperCase()}</div>\n\n                      <div style={{fontSize:9,color:'#8899AA',textTransform:'uppercase' as const,fontWeight:700,letterSpacing:0.6,margin:'16px 0 10px'}}>🔐 Security Events</div>\n                      {(previewData.securityTimeline||[]).length===0?<div style={{fontSize:10,color:'#8899AA'}}>No security events.</div>:(\n                        <div style={{display:'flex',flexDirection:'column' as const,gap:6}}>\n                          {previewData.securityTimeline.slice(0,8).map((e:any,i:number)=>(\n                            <div key={i} style={{fontSize:10,color:'#8899AA'}}>\n                              <span style={{color:e.status==='failed'?'#FF4757':'#00C48C'}}>●</span> {e.action} <span style={{color:'#8899AA'}}>· {e.at?new Date(e.at).toLocaleDateString('en-IN'):''}</span>\n                            </div>\n                          ))}\n                        </div>\n                      )}\n                    </div>\n                  </div>\n                  )}\n                </div>\n              )}\n";
